    HINDRANCES: [
      // --- Major ---
      { id: 'pi_branded', name: 'Branded', type: 'Major', description: 'You bear a brand marking you as a pirate. -2 Persuasion among law-abiding folk. If caught by authorities, you will be executed. Some wear it with pride.' },
      { id: 'pi_cursedTreasure', name: 'Cursed Treasure', type: 'Major', description: 'You took something you shouldn\'t have. Bad luck follows: -1 to all Trait rolls until the curse is lifted through a quest or powerful magic.' },
      { id: 'pi_markedByTheDeep', name: 'Marked by the Deep', type: 'Major', description: 'Sea creatures are drawn to attack you. Krakens, sharks, and sea serpents single you out in encounters. Something about you calls to the deep.' },
      { id: 'pi_oneArm', name: 'One Arm', type: 'Major', description: 'Lost an arm to battle or misadventure. -4 to tasks requiring two hands. Can only carry one weapon. Common among old pirates.' },
      { id: 'pi_oneEye', name: 'One Eye', type: 'Major', description: 'Lost an eye. -1 Persuasion without a patch. -2 to all rolls requiring depth perception (Shooting at medium/long range, catching thrown objects).' },
      { id: 'pi_oneLeg', name: 'One Leg', type: 'Major', description: 'Lost a leg. With peg leg: Pace 4, d4 running die. Without: Pace 2, -2 to all mobility rolls, -2" Swimming Pace. The mark of a seasoned buccaneer.',
        special: { paceSet: 4, runDie: 4 } },
      { id: 'pi_seasick', name: 'Seasick', type: 'Major', description: 'Vigor check when boarding a ship. Failure means -2 to all Trait rolls until 1 hour on dry land. -2/-4 additional penalty in storms. The worst affliction for a would-be sailor.' },
      // --- Minor ---
      { id: 'pi_jingoistic', name: 'Jingoistic', type: 'Minor', description: '-2 Persuasion with people of other nationalities or races. You believe your people are superior. Can be taken as Major for -4.' },
      { id: 'pi_landLubber', name: 'Landlubber', type: 'Minor', description: 'Cannot buy Boating during character creation. -2 to all Boating rolls permanently. You just don\'t belong on the water.' },
      { id: 'pi_pegLeg', name: 'Peg Leg', type: 'Minor', description: 'Pace 5, d4 running die. -2 to Athletics involving legs. Your wooden leg makes you unsteady but adds to the pirate mystique.',
        special: { paceSet: 5, runDie: 4 } },
      { id: 'pi_squanderous', name: 'Squanderous', type: 'Minor', description: 'Carousing costs are doubled. You can\'t hold onto coin \u2014 every port is a chance to blow your share on drink, dice, and dubious company.' },
      { id: 'pi_superstitious', name: 'Superstitious', type: 'Minor', description: 'Must follow sailor superstitions (no whistling aboard, no sailing on Friday, etc.) or suffer -1 to all rolls from crippling anxiety.' },
    ],

